html:
{# UAE End of Service Benefit - Print Format
   Designed to match the sample EOSB document layout #}

<style>
    .eosb-print {
        font-family: Arial, Helvetica, sans-serif;
        font-size: 12px;
        color: #000;
        max-width: 800px;
        margin: 0 auto;
        padding: 20px;
    }
    .eosb-print h1 {
        text-align: center;
        font-size: 18px;
        margin-bottom: 5px;
        text-transform: uppercase;
    }
    .eosb-print h2 {
        text-align: center;
        font-size: 13px;
        font-weight: normal;
        margin-top: 0;
        margin-bottom: 20px;
        color: #555;
    }
    .eosb-print table {
        width: 100%;
        border-collapse: collapse;
        margin-bottom: 12px;
    }
    .eosb-print table.section-table th {
        background: #2c3e50;
        color: #fff;
        padding: 6px 10px;
        text-align: left;
        font-size: 12px;
        text-transform: uppercase;
        letter-spacing: 0.5px;
    }
    .eosb-print table.section-table td {
        padding: 5px 10px;
        border-bottom: 1px solid #e0e0e0;
        vertical-align: top;
    }
    .eosb-print table.section-table td.label {
        width: 60%;
        font-weight: 500;
    }
    .eosb-print table.section-table td.value {
        width: 40%;
        text-align: right;
        font-family: 'Courier New', monospace;
    }
    .eosb-print .highlight-row td {
        background: #ecf0f1;
        font-weight: bold;
        font-size: 13px;
    }
    .eosb-print .total-eosb {
        background: #27ae60 !important;
        color: white !important;
        font-size: 14px !important;
    }
    .eosb-print .info-table td {
        padding: 4px 8px;
        font-size: 12px;
    }
    .eosb-print .info-table td.field-label {
        font-weight: bold;
        background: #f4f6f7;
        width: 40%;
    }
    .eosb-print .declaration {
        margin-top: 25px;
        margin-bottom: 25px;
        padding: 12px;
        border: 1px solid #ccc;
        background: #fafafa;
        font-size: 11px;
        line-height: 1.5;
        text-align: justify;
    }
    .eosb-print .signatures {
        width: 100%;
        margin-top: 35px;
    }
    .eosb-print .signatures td {
        width: 25%;
        text-align: center;
        padding-top: 50px;
        border-top: 1px solid #000;
        font-size: 11px;
        font-weight: bold;
        vertical-align: top;
    }
    .eosb-print .sig-name {
        display: block;
        margin-bottom: 2px;
    }
    .eosb-print .sig-role {
        display: block;
        font-weight: normal;
        color: #666;
        font-size: 10px;
    }
    .eosb-print .footer-meta {
        margin-top: 20px;
        font-size: 10px;
        color: #888;
        text-align: center;
        border-top: 1px solid #eee;
        padding-top: 8px;
    }
</style>

<div class="eosb-print">

    <h1>End of Service Benefit Calculation</h1>
    <h2>{{ doc.company }} &nbsp;|&nbsp; United Arab Emirates</h2>
    <h2 style="margin-top:-15px;">As per UAE Federal Decree-Law No. 33 of 2021</h2>

    {# ---- Employee Header Block ---- #}
    <table class="info-table" border="1" style="border-collapse:collapse; width:100%;">
        <tr>
            <td class="field-label">EMPLOYEE NAME</td>
            <td>{{ doc.employee_name or '' }}</td>
            <td class="field-label">EMPLOYEE ID</td>
            <td>{{ doc.employee or '' }}</td>
        </tr>
        <tr>
            <td class="field-label">DESIGNATION</td>
            <td>{{ doc.designation or '' }}</td>
            <td class="field-label">DEPARTMENT</td>
            <td>{{ doc.department or '' }}</td>
        </tr>
        <tr>
            <td class="field-label">EXIT STATUS</td>
            <td>{{ doc.exit_status or '' }}</td>
            <td class="field-label">NATIONALITY</td>
            <td>{{ doc.nationality or '' }}</td>
        </tr>
        <tr>
            <td class="field-label">DATE OF JOINING</td>
            <td>{{ frappe.utils.formatdate(doc.date_of_joining) if doc.date_of_joining else '' }}</td>
            <td class="field-label">DATE OF SETTLEMENT</td>
            <td>{{ frappe.utils.formatdate(doc.date_of_settlement) if doc.date_of_settlement else '' }}</td>
        </tr>
        <tr>
            <td class="field-label">EMIRATES ID</td>
            <td>{{ doc.emirates_id or '' }}</td>
            <td class="field-label">PASSPORT NUMBER</td>
            <td>{{ doc.passport_number or '' }}</td>
        </tr>
    </table>

    {# ---- Salary As On Settlement Date ---- #}
    <table class="section-table">
        <tr><th colspan="2">Salary As On Settlement Date</th></tr>
        <tr><td class="label">Basic Salary</td><td class="value">{{ "%.2f"|format(doc.basic_salary or 0) }}</td></tr>
        <tr><td class="label">Housing Allowance</td><td class="value">{{ "%.2f"|format(doc.housing_allowance or 0) }}</td></tr>
        <tr><td class="label">Transportation Allowance</td><td class="value">{{ "%.2f"|format(doc.transportation_allowance or 0) }}</td></tr>
        <tr><td class="label">Other Allowance</td><td class="value">{{ "%.2f"|format(doc.other_allowance or 0) }}</td></tr>
        <tr class="highlight-row"><td class="label">GROSS PAY PER MONTH (AED)</td><td class="value">{{ "%.2f"|format(doc.gross_pay_per_month or 0) }}</td></tr>
    </table>

    {# ---- Gratuity ---- #}
    <table class="section-table">
        <tr><th colspan="2">Gratuity</th></tr>
        <tr><td class="label">Employment Years</td><td class="value">{{ "%.4f"|format(doc.employment_years or 0) }}</td></tr>
        <tr><td class="label">Total Service Days</td><td class="value">{{ doc.total_service_days or 0 }}</td></tr>
        <tr><td class="label">Gratuity Base ({{ doc.gratuity_base_type or 'Basic Only' }})</td><td class="value">{{ "%.2f"|format(doc.gratuity_base_amount or 0) }}</td></tr>
        <tr><td class="label">Daily Basic Wage (Base ÷ 30)</td><td class="value">{{ "%.2f"|format(doc.daily_basic_wage or 0) }}</td></tr>
        <tr><td class="label">Gratuity Days Per Year Applied</td><td class="value">{{ doc.gratuity_days_per_year or 0 }}</td></tr>
        {% if doc.gratuity_reduction_percent %}
        <tr><td class="label">Gratuity Reduction Applied</td><td class="value">{{ doc.gratuity_reduction_percent }}%</td></tr>
        {% endif %}
        <tr class="highlight-row"><td class="label">GRATUITY PAYABLE FOR TOTAL DAYS WORKED</td><td class="value">{{ "%.2f"|format(doc.gratuity_payable or 0) }}</td></tr>
    </table>

    {# ---- Annual Leave Adjustment ---- #}
    <table class="section-table">
        <tr><th colspan="2">Annual Leave Adjustment</th></tr>
        <tr><td class="label">Leaves Accrued</td><td class="value">{{ "%.2f"|format(doc.leaves_accrued or 0) }}</td></tr>
        <tr><td class="label">Leaves Utilized</td><td class="value">{{ "%.2f"|format(doc.leaves_utilized or 0) }}</td></tr>
        <tr><td class="label">Leaves Balance</td><td class="value">{{ "%.2f"|format(doc.leaves_balance or 0) }}</td></tr>
        <tr><td class="label">Leave Calculation Basis</td><td class="value" style="font-family:Arial; text-align:right;">{{ doc.leave_calculation_basis or '' }}</td></tr>
        <tr><td class="label">Leave Daily Rate</td><td class="value">{{ "%.2f"|format(doc.leave_daily_rate or 0) }}</td></tr>
        {% if doc.leave_salary_held_visa_change %}
        <tr><td class="label">Leave Salary Held In Case Of Visa Change</td><td class="value">{{ "%.2f"|format(doc.leave_salary_held_visa_change) }}</td></tr>
        {% endif %}
        {% if doc.leave_salary_paid %}
        <tr><td class="label">Leave Salary Already Paid</td><td class="value">{{ "%.2f"|format(doc.leave_salary_paid) }}</td></tr>
        {% endif %}
        <tr class="highlight-row"><td class="label">LEAVE SALARY PAYABLE</td><td class="value">{{ "%.2f"|format(doc.leave_salary_payable or 0) }}</td></tr>
    </table>

    {# ---- Overtime Payment ---- #}
    {% if doc.overtime_payable or doc.pending_overtime_hours %}
    <table class="section-table">
        <tr><th colspan="2">Overtime Payment</th></tr>
        <tr><td class="label">Pending Overtime Hours</td><td class="value">{{ "%.2f"|format(doc.pending_overtime_hours or 0) }}</td></tr>
        <tr><td class="label">Overtime Rate Per Hour</td><td class="value">{{ "%.2f"|format(doc.overtime_rate_per_hour or 0) }}</td></tr>
        {% if doc.overtime_notes %}
        <tr><td class="label">Notes</td><td class="value" style="font-family:Arial; text-align:right;">{{ doc.overtime_notes }}</td></tr>
        {% endif %}
        <tr class="highlight-row"><td class="label">OVERTIME PAYABLE</td><td class="value">{{ "%.2f"|format(doc.overtime_payable or 0) }}</td></tr>
    </table>
    {% endif %}

    {# ---- Pending Salary & Allowances ---- #}
    <table class="section-table">
        <tr><th colspan="2">Pending Salary & Allowances</th></tr>
        <tr><td class="label">Days Worked For Which Salary Is Pending</td><td class="value">{{ doc.days_worked_pending or 0 }}</td></tr>
        {% if doc.unpaid_leaves_taken %}
        <tr><td class="label">Unpaid Leaves Taken During This Period</td><td class="value">{{ "%.2f"|format(doc.unpaid_leaves_taken) }}</td></tr>
        {% endif %}
        <tr><td class="label">Pending Salary For The Last Month Worked</td><td class="value">{{ "%.2f"|format(doc.pending_salary_last_month or 0) }}</td></tr>
        <tr><td class="label">Air Ticket Allowance</td><td class="value">{{ "%.2f"|format(doc.air_ticket_allowance or 0) }}</td></tr>
        <tr class="highlight-row"><td class="label">SALARY PAYABLE</td><td class="value">{{ "%.2f"|format(doc.salary_payable or 0) }}</td></tr>
    </table>

    {# ---- Recovery ---- #}
    <table class="section-table">
        <tr><th colspan="2">Recovery / Deductions</th></tr>
        <tr><td class="label">Visa / Labour Card Expense</td><td class="value">{{ "%.2f"|format(doc.visa_labour_card_expense or 0) }}</td></tr>
        <tr><td class="label">Loan / Advance Recovery</td><td class="value">{{ "%.2f"|format(doc.loan_advance_recovery or 0) }}</td></tr>
        <tr><td class="label">Notice Period Shortfall</td><td class="value">{{ "%.2f"|format(doc.notice_period_shortfall or 0) }}</td></tr>
        <tr><td class="label">Other Recovery</td><td class="value">{{ "%.2f"|format(doc.other_recovery or 0) }}</td></tr>
        <tr class="highlight-row"><td class="label">TOTAL RECOVERY</td><td class="value">{{ "%.2f"|format(doc.total_recovery or 0) }}</td></tr>
    </table>

    {# ---- Final Total ---- #}
    <table class="section-table">
        <tr>
            <td class="label total-eosb" style="padding:10px;">TOTAL END OF SERVICE BENEFIT (AED)</td>
            <td class="value total-eosb" style="padding:10px;">{{ "%.2f"|format(doc.net_payable or 0) }}</td>
        </tr>
    </table>

    {# ---- Declaration ---- #}
    <div class="declaration">
        {{ doc.acknowledgement_text or 'I confirm that I agree and accept the amount as calculated above as my full and final settlement.' }}
    </div>

    {# ---- Signatures ---- #}
    <table class="signatures">
        <tr>
            <td>
                <span class="sig-name">{{ doc.employee_name or '' }}</span>
                <span class="sig-role">Employee</span>
            </td>
            <td>
                <span class="sig-name">_______________</span>
                <span class="sig-role">HR Executive</span>
            </td>
            <td>
                <span class="sig-name">_______________</span>
                <span class="sig-role">CPO</span>
            </td>
            <td>
                <span class="sig-name">_______________</span>
                <span class="sig-role">Head of Finance</span>
            </td>
        </tr>
    </table>

    <div class="footer-meta">
        Document: {{ doc.name }} &nbsp;|&nbsp; Status: {{ doc.status or 'Draft' }} &nbsp;|&nbsp; Generated: {{ frappe.utils.formatdate(frappe.utils.nowdate()) }}
    </div>

</div>
